import { SignJWT, jwtVerify, type JWTPayload } from "jose";

const textEncoder = new TextEncoder();

function getJwtSecret(): Uint8Array {
  const secret = process.env.JWT_SECRET;
  if (!secret) {
    throw new Error(
      "JWT_SECRET is required. TODO: set a user-managed secret in environment variables.",
    );
  }

  return textEncoder.encode(secret);
}

export async function signAccessToken(
  payload: JWTPayload,
  expiresIn = "1h",
): Promise<string> {
  const secret = getJwtSecret();

  return new SignJWT(payload)
    .setProtectedHeader({ alg: "HS256", typ: "JWT" })
    .setIssuedAt()
    .setExpirationTime(expiresIn)
    .sign(secret);
}

export async function verifyAccessToken(
  token: string,
): Promise<JWTPayload | null> {
  try {
    const secret = getJwtSecret();
    const { payload } = await jwtVerify(token, secret);
    return payload;
  } catch {
    return null;
  }
}

import { getBearerToken } from "./bearer";
import { getSessionToken } from "./session";

interface HeadersLike {
  get(name: string): string | null;
}

interface RequestWithAuthSources {
  headers: HeadersLike;
  cookies: {
    get(name: string): { value: string } | undefined;
  };
}

export function getRequestToken(request: RequestWithAuthSources): string | null {
  const bearerToken = getBearerToken(request.headers.get("authorization"));
  if (bearerToken) {
    return bearerToken;
  }

  return getSessionToken(request);
}

const SESSION_COOKIE_NAME = "skynet_access_token";
const SESSION_MAX_AGE_SECONDS = 60 * 60;

interface CookieValue {
  value: string;
}

interface CookieStoreLike {
  get(name: string): CookieValue | undefined;
}

interface RequestWithCookies {
  cookies: CookieStoreLike;
}

export interface SessionCookie {
  name: string;
  value: string;
  httpOnly: true;
  sameSite: "lax";
  secure: boolean;
  path: "/";
  maxAge: number;
}

function baseSessionCookie(): Omit<SessionCookie, "value" | "maxAge"> {
  return {
    name: SESSION_COOKIE_NAME,
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
  };
}

export function buildSessionCookie(token: string): SessionCookie {
  return {
    ...baseSessionCookie(),
    value: token,
    maxAge: SESSION_MAX_AGE_SECONDS,
  };
}

export function buildClearedSessionCookie(): SessionCookie {
  return {
    ...baseSessionCookie(),
    value: "",
    maxAge: 0,
  };
}

export function getSessionToken(request: RequestWithCookies): string | null {
  return request.cookies.get(SESSION_COOKIE_NAME)?.value ?? null;
}

import { NextRequest, NextResponse } from "next/server";

import { signAccessToken } from "@/lib/auth/jwt";
import { buildSessionCookie } from "@/lib/auth/session";
import type { ApiErrorResponse } from "@skynet/sdk";

interface TokenRequestBody {
  sub?: string;
  username?: string;
  role?: "engineer" | "pm" | "designer" | "operator";
}

interface TokenResponse {
  accessToken: string;
  tokenType: "Bearer";
  expiresIn: "1h";
}

function badRequest(message: string): NextResponse<ApiErrorResponse> {
  return NextResponse.json(
    { error: { code: "BAD_REQUEST", message } },
    { status: 400 },
  );
}

export async function POST(request: NextRequest): Promise<NextResponse> {
  let body: TokenRequestBody;
  try {
    body = (await request.json()) as TokenRequestBody;
  } catch {
    return badRequest("Request body must be valid JSON");
  }

  if (!body.sub) {
    return badRequest("`sub` is required to issue a JWT");
  }

  try {
    const accessToken = await signAccessToken({
      sub: body.sub,
      username: body.username,
      role: body.role,
    });

    const responseBody: TokenResponse = {
      accessToken,
      tokenType: "Bearer",
      expiresIn: "1h",
    };

    const response = NextResponse.json(responseBody, { status: 201 });
    response.cookies.set(buildSessionCookie(accessToken));
    return response;
  } catch (error) {
    const message =
      error instanceof Error
        ? error.message
        : "Server JWT configuration is missing";

    const apiError: ApiErrorResponse = {
      error: {
        code: "SERVER_MISCONFIGURED",
        message,
      },
    };

    return NextResponse.json(apiError, { status: 500 });
  }
}

